import{_ as i,c as s,o as n,ag as e}from"./chunks/framework.DPDPlp3K.js";const k=JSON.parse('{"title":"neovim概述","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/软件/neovim.md","filePath":"计算机/软件/neovim.md","lastUpdated":null}'),l={name:"计算机/软件/neovim.md"};function t(p,a,o,r,h,d){return n(),s("div",null,a[0]||(a[0]=[e(`<h1 id="neovim概述" tabindex="-1">neovim概述 <a class="header-anchor" href="#neovim概述" aria-label="Permalink to &quot;neovim概述&quot;">​</a></h1><p>neovim 是一款基于 Vim 的现代化、可扩展的文本编辑器, 搭配合适的插件可以实现IDE的功能(类似vscode的功能)</p><p>vim基于模式编辑（mode editing）的思想, 高效地利用快捷键, 在编辑文档时, 可以脱离对鼠标的依赖.</p><h2 id="常用的命令" tabindex="-1">常用的命令 <a class="header-anchor" href="#常用的命令" aria-label="Permalink to &quot;常用的命令&quot;">​</a></h2><p>使用<code>:</code>开启命令模式，然后可以输入命令。</p><ul><li><code>= vim.fn.stdpath(&quot;config&quot;)</code> 打印配置文件所在的路径</li><li><code>e &lt;filename&gt;</code> 打开或创建新文件</li><li><code>w filename</code> 保存文件为</li></ul><h2 id="neovim的插件管理" tabindex="-1">neovim的插件管理 <a class="header-anchor" href="#neovim的插件管理" aria-label="Permalink to &quot;neovim的插件管理&quot;">​</a></h2><p>neovim可以扩展各种各样的插件提高工作效率, 管理插件的插件称为插件管理器。<a href="https://fungzhenhua.github.io/2024/06/06/Neovim%E7%9A%84%E6%8F%92%E4%BB%B6%E7%AE%A1%E7%90%86%E5%99%A8/" target="_blank" rel="noreferrer">Neovim 有各种各样的插件管理器</a></p><h2 id="lazyvim插件管理器" tabindex="-1">lazyvim插件管理器 <a class="header-anchor" href="#lazyvim插件管理器" aria-label="Permalink to &quot;lazyvim插件管理器&quot;">​</a></h2><ul><li>lazyvim 是一个为Neovim提供快速启动配置的项目，使其易于进行自定义和扩展.</li><li>lazy.nvim 通过 git 管理各个插件，</li><li>lazyvim使用空格作为前缀键, 后面跟不同的键有不同的功能. 在打开的文件之间, 缓冲区(标签)之间切换: H L</li><li>输入<code>Mason</code>命令可以打开插件面板</li></ul><h3 id="lazyvim的安装和配置" tabindex="-1">lazyvim的安装和配置 <a class="header-anchor" href="#lazyvim的安装和配置" aria-label="Permalink to &quot;lazyvim的安装和配置&quot;">​</a></h3><ul><li>lazyvim的安装和配置参考<a href="https://www.lazyvim.org/" target="_blank" rel="noreferrer">官方文档</a></li><li>neovim的配置文件在<code>~/.config/nvim/</code>目录下，目录结构如下：</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/nvim</span></span>
<span class="line"><span>├── lua</span></span>
<span class="line"><span>│   ├── config</span></span>
<span class="line"><span>│   │   ├── autocmds.lua</span></span>
<span class="line"><span>│   │   ├── keymaps.lua</span></span>
<span class="line"><span>│   │   ├── lazy.lua      # 关于lazy.nvim的配置</span></span>
<span class="line"><span>│   │   └── options.lua</span></span>
<span class="line"><span>│   └── plugins</span></span>
<span class="line"><span>│       ├── spec1.lua</span></span>
<span class="line"><span>│       ├── ...</span></span>
<span class="line"><span>│       └── spec2.lua</span></span>
<span class="line"><span>└── init.lua              # neovim配置的入口文件</span></span></code></pre></div><ul><li>init.lua 是入口文件, nvim启动时会加载 init.lua 中的配置，然后通过<code>require(&quot;config.lazy&quot;)</code>查找当前目录下的<code>lua/config/</code>目录下的lazy.lua文件，运行其内容。</li><li>lazy.lua文件中使用<code>{ import = &quot;plugins&quot; }</code>语句导入<code>lua/plugins</code>目录下的插件.</li><li>一般基础的配置在 config 目录, 额外的插件在 plugins 目录.</li><li>./lua/plugins 下的所有采用如下形式，彼此独立，互不影响，因此高度可移植.</li></ul><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;folke/which-key.nvim&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">--插件的 git 仓库的位置。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  dependencies </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;folke/which-key.nvim&quot; </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">--插件的依赖项</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  config</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> function</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">--config 是插件加载完毕后要运行的函数，通常将有关插件的配置写在此处</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;which-key&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">setup</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {}</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  end</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="删除lazyvim及其文件" tabindex="-1">删除lazyvim及其文件 <a class="header-anchor" href="#删除lazyvim及其文件" aria-label="Permalink to &quot;删除lazyvim及其文件&quot;">​</a></h3><p>主要是删除这些文件:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/nvim (LazyVim config)</span></span>
<span class="line"><span>~/.local/share/nvim (用户数据目录下，这里有lazy安装的插件和mason安装的包)</span></span>
<span class="line"><span>~/.local/state/nvim (Session state directory: storage for file drafts, swap, undo, shada.)</span></span>
<span class="line"><span>~/.cache/nvim (Neovim cache)</span></span></code></pre></div><h3 id="好用的插件" tabindex="-1">好用的插件 <a class="header-anchor" href="#好用的插件" aria-label="Permalink to &quot;好用的插件&quot;">​</a></h3><h4 id="img-clip" tabindex="-1">img-clip <a class="header-anchor" href="#img-clip" aria-label="Permalink to &quot;img-clip&quot;">​</a></h4><p>img-clip 能够方便地将图像嵌入如 LaTeX，Markdown 或 Typst 等标记语言: 直接从系统剪贴板粘贴图像, 从Web浏览器或文件资源管理器中拖拽图像, 将图像嵌入为文件、Web URL 或 Base64 编码的数据.</p><p>GitHub: <a href="https://github.com/HakonHarnes/img-clip.nvim" target="_blank" rel="noreferrer">img-clip.nvim</a></p><h4 id="markdown-preview" tabindex="-1">markdown-preview <a class="header-anchor" href="#markdown-preview" aria-label="Permalink to &quot;markdown-preview&quot;">​</a></h4><p>markdown-preview 能够在浏览器中预览 Markdown，支持同步滚动和即使刷新.</p><p>GitHub: <a href="https://github.com/iamcco/markdown-preview.nvim" target="_blank" rel="noreferrer">markdown-preview.nvim</a></p><p>使用<code>MarkdownPreviwe</code>命令开启预览.</p><h4 id="render-markdown" tabindex="-1">render-markdown <a class="header-anchor" href="#render-markdown" aria-label="Permalink to &quot;render-markdown&quot;">​</a></h4><p>提升Markdown文件查看体验</p><p>GitHub: <a href="https://github.com/MeanderingProgrammer/render-markdown.nvim" target="_blank" rel="noreferrer">render-markdown.nvim</a></p><h4 id="snacks" tabindex="-1">snacks <a class="header-anchor" href="#snacks" aria-label="Permalink to &quot;snacks&quot;">​</a></h4><p>snacks 是一个为 Neovim 设计的插件集合，旨在提供一系列提升用户体验的小插件。</p><p>GitHub: <a href="https://github.com/folke/snacks.nvim" target="_blank" rel="noreferrer">snacks.nvim</a></p><p>包含了image插件, 是使用 Kitty 图形协议的图像查看器。</p>`,33)]))}const m=i(l,[["render",t]]);export{k as __pageData,m as default};
